const paquetes = $input.all();

return paquetes.map(item => {

    let correo = "";
    let asunto = "";
    let mensajeHTML = "";

    switch (item.json.destinatario) {

        case "Analista":

            correo = "analista@ejemplo.com";

            asunto = "Resultado de Ejecución | Pipeline de Conciliación Bancaria";

            mensajeHTML = `
<p>Buen día.</p>

<p>La ejecución automática del <strong>Pipeline de Conciliación Bancaria</strong> ha finalizado correctamente.</p>

<p>Se adjuntan todos los artefactos generados para validar la ejecución del proceso.</p>

<p>Cordialmente,<br><strong>Automatización de Conciliación Bancaria</strong></p>
`;

            break;

        case "Gerencia de Riesgo":

            correo = "riesgo@ejemplo.com";

            asunto = "Reporte Ejecutivo | Conciliación Bancaria";

            mensajeHTML = `
<p>Buen día.</p>

<p>Se comparte el paquete ejecutivo generado por el proceso automatizado de conciliación bancaria.</p>

<p>Los archivos adjuntos apoyan el análisis de riesgos y la toma de decisiones.</p>

<p>Cordialmente,<br><strong>Automatización de Conciliación Bancaria</strong></p>
`;

            break;

        case "Equipo Operativo de Cartera":

            correo = "cartera@ejemplo.com";

            asunto = "Alertas Operativas | Conciliación Bancaria";

            mensajeHTML = `
<p>Buen día.</p>

<p>Se adjuntan el dataset limpio y la clasificación de alertas para apoyar la gestión operativa de cartera.</p>

<p>Cordialmente,<br><strong>Automatización de Conciliación Bancaria</strong></p>
`;

            break;

    }

    return {
        json: {
            ...item.json,
            correo,
            asunto,
            mensaje_html: mensajeHTML
        }
    };

});

const outputDir = $input.first().json.output_dir;

return [
  {
    json: {
      output_dir: outputDir,
      artefactos: [
        {
          nombre: "reporte_ejecutivo",
          archivo: "reporte_ejecutivo.md",
          ruta: `${outputDir}/reporte_ejecutivo.md`,
          tipo: "markdown"
        },
        {
          nombre: "reporte_estructurado",
          archivo: "reporte_estructurado.xlsx",
          ruta: `${outputDir}/reporte_estructurado.xlsx`,
          tipo: "excel"
        },
        {
          nombre: "datos_limpios",
          archivo: "datos_limpios.xlsx",
          ruta: `${outputDir}/datos_limpios.xlsx`,
          tipo: "excel"
        },
        {
          nombre: "clasificacion_alertas",
          archivo: "clasificacion_alertas.json",
          ruta: `${outputDir}/clasificacion_alertas.json`,
          tipo: "json"
        },
        {
          nombre: "grafico_ingresos_egresos",
          archivo: "1_ingresos_egresos.png",
          ruta: `${outputDir}/graficas_output/1_ingresos_egresos.png`,
          tipo: "imagen"
        },
        {
          nombre: "grafico_problemas_banco",
          archivo: "2_problemas_banco.png",
          ruta: `${outputDir}/graficas_output/2_problemas_banco.png`,
          tipo: "imagen"
        },
        {
          nombre: "grafico_mora_empresa",
          archivo: "3_mora_empresa.png",
          ruta: `${outputDir}/graficas_output/3_mora_empresa.png`,
          tipo: "imagen"
        },
        {
          nombre: "grafico_heatmap_bancos",
          archivo: "4_heatmap_bancos.png",
          ruta: `${outputDir}/graficas_output/4_heatmap_bancos.png`,
          tipo: "imagen"
        }
      ]
    }
  }
];

const catalogo = $input.first().json.artefactos;

return [
  {
    json: {
      destinatario: "Analista",
      artefactos: catalogo
    }
  },
  {
    json: {
      destinatario: "Gerencia de Riesgo",
      artefactos: catalogo.filter(a =>
        [
          "reporte_ejecutivo",
          "datos_limpios",
          "grafico_ingresos_egresos",
          "grafico_problemas_banco",
          "grafico_mora_empresa",
          "grafico_heatmap_bancos"
        ].includes(a.nombre)
      )
    }
  },
  {
    json: {
      destinatario: "Equipo Operativo de Cartera",
      artefactos: catalogo.filter(a =>
        [
          "datos_limpios",
          "clasificacion_alertas"
        ].includes(a.nombre)
      )
    }
  }
];

const salida = [];

for (const item of $input.all()) {

  const {
    artefactos,
    ...datosCorreo
  } = item.json;

  for (const artefacto of artefactos) {

    salida.push({
      json: {
        ...datosCorreo,
        artefacto
      }
    });

  }

}

return salida;

const previos = $("Expandir Artefactos").all(); // items originales (correo, asunto, artefacto...)
const actuales = $input.all();                  // items con el binario del archivo leído

const grupos = {};

for (let i = 0; i < actuales.length; i++) {
  const orig = previos[i].json;
  const bin = actuales[i].binary;

  const key = orig.destinatario;
  if (!grupos[key]) {
    grupos[key] = {
      json: {
        destinatario: orig.destinatario,
        correo: orig.correo,
        asunto: orig.asunto,
        mensaje_html: orig.mensaje_html,
        adjuntos: []
      },
      binary: {}
    };
  }

  // nombre único de propiedad binaria por artefacto
  const propName = orig.artefacto.nombre;
  const binKey = Object.keys(bin)[0]; // normalmente "data"
  grupos[key].binary[propName] = bin[binKey];
  grupos[key].json.adjuntos.push(propName);
}

return Object.values(grupos).map(item => ({
  json: {
    ...item.json,
    // string listo para el campo "Attachments" del nodo Gmail
    attachmentPropertyNames: item.json.adjuntos.join(",")
  },
  binary: item.binary
}));
